using UnityEngine;
using System.Collections.Generic;

// Find all RangeIndicator objects and check their properties
var results = new List<string>();

foreach (var t in Resources.FindObjectsOfTypeAll<Transform>())
{
    if (t.name.Contains("RangeIndicator") || t.name.Contains("SkillButton") || t.name.Contains("LightningSkill"))
    {
        var go = t.gameObject;
        var lr = go.GetComponent<LineRenderer>();
        var sr = go.GetComponent<SpriteRenderer>();
        var renderer = go.GetComponent<Renderer>();

        results.Add($"[{go.name}] active={go.activeSelf}/{go.activeInHierarchy} layer={go.layer} pos={t.position} parent={t.parent?.name ?? "root"}");

        if (lr != null)
        {
            results.Add($"  LineRenderer: sortingOrder={lr.sortingOrder} startColor={lr.startColor} startWidth={lr.startWidth} posCount={lr.positionCount} mat={lr.sharedMaterial?.name ?? "NULL"}");
        }
        if (renderer != null)
        {
            results.Add($"  Renderer: enabled={renderer.enabled} sortingLayer={renderer.sortingLayerName} sortingOrder={renderer.sortingOrder} mat={renderer.sharedMaterial?.name ?? "NULL"}");
        }
    }
}

// Also find duplicate objects in general
var nameCount = new Dictionary<string, List<int>>();
foreach (var t in Resources.FindObjectsOfTypeAll<Transform>())
{
    if (!t.gameObject.scene.isLoaded) continue;
    var name = t.name;
    if (!nameCount.ContainsKey(name)) nameCount[name] = new List<int>();
    nameCount[name].Add(t.gameObject.GetInstanceID());
}

results.Add("\n--- DUPLICATES ---");
foreach (var kv in nameCount)
{
    if (kv.Value.Count > 1)
    {
        results.Add($"'{kv.Key}' appears {kv.Value.Count} times (IDs: {string.Join(", ", kv.Value)})");
    }
}

UnityEngine.Debug.Log(string.Join("\n", results));

using UnityEngine;
using System.Collections.Generic;

var results = new List<string>();

// Check sorting layers
results.Add("=== SORTING LAYERS ===");
var layers = SortingLayer.layers;
foreach (var l in layers)
    results.Add($"  {l.name}: id={l.id} value={l.value}");

// Check camera
var cam = Camera.main;
if (cam != null)
{
    results.Add($"\n=== CAMERA ===");
    results.Add($"  pos={cam.transform.position} ortho={cam.orthographic} size={cam.orthographicSize}");
    results.Add($"  clearFlags={cam.clearFlags} bgColor={cam.backgroundColor}");
    results.Add($"  cullingMask={cam.cullingMask}");
}

// Check all SpriteRenderers and their sorting
results.Add("\n=== SPRITE RENDERERS (by sortingOrder) ===");
var sprites = new List<SpriteRenderer>();
foreach (var sr in Resources.FindObjectsOfTypeAll<SpriteRenderer>())
{
    if (sr.gameObject.scene.isLoaded)
        sprites.Add(sr);
}
sprites.Sort((a, b) => a.sortingOrder.CompareTo(b.sortingOrder));
foreach (var sr in sprites)
{
    results.Add($"  [{sr.name}] layer={sr.sortingLayerName} order={sr.sortingOrder} pos={sr.transform.position}");
}

// Check all LineRenderers
results.Add("\n=== LINE RENDERERS ===");
foreach (var lr in Resources.FindObjectsOfTypeAll<LineRenderer>())
{
    if (lr.gameObject.scene.isLoaded)
        results.Add($"  [{lr.name}] order={lr.sortingOrder} layer={lr.sortingLayerName} pos={lr.transform.position} mat={lr.sharedMaterial?.name ?? "NULL"}");
}

// Check the two RangeIndicators details
results.Add("\n=== RANGE INDICATOR DETAILS ===");
foreach (var t in Resources.FindObjectsOfTypeAll<Transform>())
{
    if (t.name == "RangeIndicator" && t.gameObject.scene.isLoaded)
    {
        var go = t.gameObject;
        var lr = go.GetComponent<LineRenderer>();
        results.Add($"  ID={go.GetInstanceID()} active={go.activeSelf} pos={t.position} parent={t.parent?.name ?? "root"}");
        if (lr != null)
        {
            results.Add($"    sortingOrder={lr.sortingOrder} startColor={lr.startColor} posCount={lr.positionCount}");
            // Check if positions are valid
            if (lr.positionCount > 0)
            {
                var p0 = lr.GetPosition(0);
                var p32 = lr.positionCount > 32 ? lr.GetPosition(32) : lr.GetPosition(lr.positionCount-1);
                results.Add($"    pos[0]={p0} pos[32]={p32}");
            }
        }
    }
}

UnityEngine.Debug.Log(string.Join("\n", results));

using UnityEngine;
using System.Collections.Generic;

var deleted = new List<string>();

// 1. Find and delete duplicate RangeIndicators (keep the one with lower instanceID = earlier created)
var rangeIndicators = new List<GameObject>();
foreach (var t in Resources.FindObjectsOfTypeAll<Transform>())
{
    if (t.name == "RangeIndicator" && t.gameObject.scene.isLoaded)
        rangeIndicators.Add(t.gameObject);
}

// Sort by instanceID, keep first (original), delete rest
